function googleToken() {
  var refreshToken;
  try { refreshToken = getVar('google_refresh_token'); } catch(e) {
    return {error: 'NOT_LOGGED_IN', message: 'You are not logged in to Google. Please use /login (Telegram) or !login (Discord) to connect your Google account first.'};
  }
  var resp = httpPost('https://oauth2.googleapis.com/token', 'client_id=' + encodeURIComponent(getVar('google_client_id')) + '&client_secret=' + encodeURIComponent(getVar('google_client_secret')) + '&refresh_token=' + encodeURIComponent(refreshToken) + '&grant_type=refresh_token', {'Content-Type': 'application/x-www-form-urlencoded'});
  var t = resp.body;
  if (t.error) throw new Error('token refresh failed: ' + t.error);
  return {token: t.access_token};
}
var auth = googleToken();
if (auth.error) return JSON.stringify(auth);
var token = auth.token;
var max = args.max_results || 10;
var resp = httpGet('https://gmail.googleapis.com/gmail/v1/users/me/messages?q=' + encodeURIComponent(args.query) + '&maxResults=' + max, {'Authorization': 'Bearer ' + token});
var body = resp.body;
if (!body.messages) return JSON.stringify([]);
var results = [];
for (var i = 0; i < body.messages.length; i++) {
  var msg = httpGet('https://gmail.googleapis.com/gmail/v1/users/me/messages/' + body.messages[i].id + '?format=metadata&metadataHeaders=Subject&metadataHeaders=From&metadataHeaders=Date', {'Authorization': 'Bearer ' + token});
  var m = msg.body;
  var headers = {};
  if (m.payload && m.payload.headers) {
    for (var j = 0; j < m.payload.headers.length; j++) {
      headers[m.payload.headers[j].name] = m.payload.headers[j].value;
    }
  }
  results.push({id: m.id, subject: headers['Subject'] || '', from: headers['From'] || '', date: headers['Date'] || '', snippet: m.snippet || ''});
}
return JSON.stringify(results, null, 2);

function googleToken() {
  var refreshToken;
  try { refreshToken = getVar('google_refresh_token'); } catch(e) {
    return {error: 'NOT_LOGGED_IN', message: 'You are not logged in to Google. Please use /login (Telegram) or !login (Discord) to connect your Google account first.'};
  }
  var resp = httpPost('https://oauth2.googleapis.com/token', 'client_id=' + encodeURIComponent(getVar('google_client_id')) + '&client_secret=' + encodeURIComponent(getVar('google_client_secret')) + '&refresh_token=' + encodeURIComponent(refreshToken) + '&grant_type=refresh_token', {'Content-Type': 'application/x-www-form-urlencoded'});
  var t = resp.body;
  if (t.error) throw new Error('token refresh failed: ' + t.error);
  return {token: t.access_token};
}
var auth = googleToken();
if (auth.error) return JSON.stringify(auth);
var token = auth.token;
var resp = httpGet('https://gmail.googleapis.com/gmail/v1/users/me/messages/' + args.message_id + '?format=full', {'Authorization': 'Bearer ' + token});
var m = resp.body;
var headers = {};
if (m.payload && m.payload.headers) {
  for (var i = 0; i < m.payload.headers.length; i++) {
    headers[m.payload.headers[i].name] = m.payload.headers[i].value;
  }
}
function getBody(payload) {
  if (payload.body && payload.body.data) {
    return atob(payload.body.data.replace(/-/g, '+').replace(/_/g, '/'));
  }
  if (payload.parts) {
    for (var i = 0; i < payload.parts.length; i++) {
      if (payload.parts[i].mimeType === 'text/plain') {
        return atob(payload.parts[i].body.data.replace(/-/g, '+').replace(/_/g, '/'));
      }
    }
    for (var i = 0; i < payload.parts.length; i++) {
      var r = getBody(payload.parts[i]);
      if (r) return r;
    }
  }
  return '';
}
return JSON.stringify({id: m.id, subject: headers['Subject'] || '', from: headers['From'] || '', to: headers['To'] || '', date: headers['Date'] || '', body: getBody(m.payload)}, null, 2);
